// frontend/src/pages/Campaign.jsx — Member 3
// Campaign Detail Page: Contribute + Withdraw

import { useState, useEffect } from "react";
import { getCrowdfundingContract, fromWei, toWei, isDeadlinePassed } from "../utils/contracts";

export default function Campaign({ campaign, user, onBack }) {
  const [detail, setDetail]           = useState(campaign);
  const [myContribution, setMyContribution] = useState("0");
  const [amount, setAmount]           = useState("");
  const [loading, setLoading]         = useState(false);
  const [error, setError]             = useState("");
  const [status, setStatus]           = useState("");

  useEffect(() => { loadDetail(); }, []);

  async function loadDetail() {
    try {
      const contract = await getCrowdfundingContract();
      const c = await contract.getCampaign(campaign.id);
      setDetail(c);
      const mine = await contract.getContribution(campaign.id, user.address);
      setMyContribution(fromWei(mine));
    } catch (err) {
      setError("Failed to load campaign: " + err.message);
    }
  }

  async function contribute() {
    if (!amount || Number(amount) <= 0) return setError("Enter a valid amount");
    try {
      setLoading(true); setError(""); setStatus("Sending contribution...");
      const contract = await getCrowdfundingContract();
      const tx = await contract.contribute(detail.id, { value: toWei(amount) });
      setStatus("Waiting for confirmation...");
      await tx.wait();
      setStatus("Contribution successful!");
      setAmount("");
      await loadDetail();
    } catch (err) {
      setError("Contribution failed: " + err.message);
    } finally { setLoading(false); }
  }

  async function withdraw() {
    try {
      setLoading(true); setError(""); setStatus("Withdrawing funds...");
      const contract = await getCrowdfundingContract();
      const tx = await contract.withdrawFunds(detail.id);
      setStatus("Waiting for confirmation...");
      await tx.wait();
      setStatus("Funds withdrawn successfully!");
      await loadDetail();
    } catch (err) {
      setError("Withdrawal failed: " + err.message);
    } finally { setLoading(false); }
  }

  const raised      = Number(fromWei(detail.amountRaised));
  const goal        = Number(fromWei(detail.goal));
  const progress    = Math.min((raised / goal) * 100, 100).toFixed(0);
  const ended       = isDeadlinePassed(detail.deadline);
  const goalReached = raised >= goal;
  const isCreator   = user.address?.toLowerCase() === detail.creator?.toLowerCase();

  return (
    <div style={{
      minHeight: "100vh",
      background: "linear-gradient(135deg, #f5f3ff 0%, #f0f9ff 100%)",
      padding: "40px 20px",
      position: "relative"
    }}>
      {/* Background decoration */}
      <div style={{
        position: "absolute",
        top: 0,
        left: 0,
        right: 0,
        height: "200px",
        background: "linear-gradient(135deg, rgba(127, 119, 221, 0.1) 0%, rgba(16, 185, 129, 0.1) 100%)",
        pointerEvents: "none"
      }} />
 
      <div style={{ maxWidth: 900, margin: "0 auto", position: "relative", zIndex: 1 }}>
        {/* Header */}
        <button onClick={onBack} style={{
          background: "none",
          border: "none",
          cursor: "pointer",
          color: "#7F77DD",
          marginBottom: 32,
          fontSize: 16,
          fontWeight: 600,
          transition: "all 0.2s ease",
          padding: "8px 0",
          display: "flex",
          alignItems: "center",
          gap: 8
        }}
        onMouseEnter={(e) => e.target.style.transform = "translateX(-4px)"}
        onMouseLeave={(e) => e.target.style.transform = "translateX(0)"}
        >
          ← Back to Campaigns
        </button>
 
        {/* Main Card */}
        <div style={styles.mainCard}>
          {/* Title & Description Section */}
          <div style={{ marginBottom: 40 }}>
            <h1 style={styles.title}>{detail.title}</h1>
            <p style={styles.description}>{detail.description}</p>
          </div>
 
          {/* Large Stats Section */}
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 24, marginBottom: 40 }}>
            {/* Raised Card */}
            <div style={styles.statCard}>
              <div style={styles.statBadge}>💰</div>
              <div style={styles.statLabel}>TOTAL RAISED</div>
              <div style={styles.statValueLarge}>{raised}</div>
              <div style={styles.statCurrency}>ETH</div>
              <div style={styles.statSubtext}>of {goal} ETH goal</div>
            </div>
 
            {/* Your Contribution Card */}
            <div style={styles.statCard}>
              <div style={styles.statBadge}>🎯</div>
              <div style={styles.statLabel}>YOUR CONTRIBUTION</div>
              <div style={styles.statValueLarge}>{myContribution}</div>
              <div style={styles.statCurrency}>ETH</div>
              <div style={styles.statSubtext}>Total pledged</div>
            </div>
          </div>
 
          {/* Progress Section */}
          <div style={{ marginBottom: 40, paddingBottom: 40, borderBottom: "1px solid rgba(127, 119, 221, 0.1)" }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
              <label style={styles.progressLabel}>FUNDING PROGRESS</label>
              <span style={styles.progressPercent}>{progress}%</span>
            </div>
            <div style={styles.progressContainer}>
              <div style={{
                ...styles.progressBar,
                width: progress + "%",
                background: goalReached
                  ? "linear-gradient(90deg, #10B981 0%, #059669 100%)"
                  : "linear-gradient(90deg, #7F77DD 0%, #6366F1 100%)",
                boxShadow: goalReached
                  ? "0 0 20px rgba(16, 185, 129, 0.4)"
                  : "0 0 20px rgba(127, 119, 221, 0.4)"
              }} />
            </div>
            <p style={styles.progressDescription}>
              {goalReached ? "🎉 Goal Reached!" : `${(goal - raised).toFixed(2)} ETH remaining`}
            </p>
          </div>
 
          {/* Status Info Card */}
          <div style={{
            ...styles.infoBox,
            borderLeftColor: ended ? "#D85A30" : "#10B981",
            marginBottom: 40
          }}>
            <div style={{ display: "flex", alignItems: "center", gap: 16 }}>
              <div style={{
                width: 14,
                height: 14,
                borderRadius: "50%",
                background: ended ? "#D85A30" : "#10B981",
                boxShadow: ended
                  ? "0 0 12px rgba(216, 90, 48, 0.3)"
                  : "0 0 12px rgba(16, 185, 129, 0.3)"
              }} />
              <div style={{ flex: 1 }}>
                <div style={styles.infoLabel}>
                  {ended ? "⏱️ Campaign Ended" : "🚀 Campaign Active"}
                </div>
                <div style={styles.infoSubtext}>
                  Deadline: {new Date(Number(detail.deadline) * 1000).toLocaleDateString("en-US", {
                    year: "numeric",
                    month: "long",
                    day: "numeric"
                  })}
                </div>
              </div>
            </div>
          </div>
 
          {/* Actions Section */}
          <div style={{ marginTop: 0 }}>
            {!ended && !goalReached && (
              <div style={{ animation: "slideUp 0.4s ease-out" }}>
                <input
                  type="number"
                  placeholder="How much ETH do you want to contribute?"
                  value={amount}
                  onChange={e => setAmount(e.target.value)}
                  style={styles.input}
                />
                <button
                  onClick={contribute}
                  disabled={loading}
                  style={{...styles.btn, ...styles.btnPrimary}}
                  onMouseEnter={(e) => !loading && (e.target.style.transform = "translateY(-2px)", e.target.style.boxShadow = "0 12px 24px rgba(127, 119, 221, 0.4)")}
                  onMouseLeave={(e) => !loading && (e.target.style.transform = "translateY(0)", e.target.style.boxShadow = "0 4px 12px rgba(127, 119, 221, 0.3)")}
                >
                  {loading ? (
                    <span style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 8 }}>
                      <span style={{ display: "inline-block", animation: "spin 1s linear infinite" }}>⏳</span>
                      Processing...
                    </span>
                  ) : (
                    "💰 Contribute Now"
                  )}
                </button>
              </div>
            )}
 
            {isCreator && goalReached && ended && !detail.withdrawn && (
              <button
                onClick={withdraw}
                disabled={loading}
                style={{...styles.btn, ...styles.btnSuccess}}
                onMouseEnter={(e) => !loading && (e.target.style.transform = "translateY(-2px)", e.target.style.boxShadow = "0 12px 24px rgba(16, 185, 129, 0.4)")}
                onMouseLeave={(e) => !loading && (e.target.style.transform = "translateY(0)", e.target.style.boxShadow = "0 4px 12px rgba(16, 185, 129, 0.3)")}
              >
                {loading ? "Processing..." : "🎉 Withdraw Funds"}
              </button>
            )}
 
            {detail.withdrawn && (
              <div style={styles.successBox}>
                <div style={{ fontSize: 32, marginRight: 16 }}>✅</div>
                <div>
                  <div style={{ fontWeight: 700, fontSize: 18, color: "#059669", marginBottom: 4 }}>
                    Funds Successfully Withdrawn
                  </div>
                  <div style={{ fontSize: 14, color: "#666" }}>
                    All funds have been transferred to the creator's wallet
                  </div>
                </div>
              </div>
            )}
 
            {ended && !goalReached && !isCreator && (
              <div style={styles.warningBox}>
                <div style={{ fontSize: 32, marginRight: 16 }}>📋</div>
                <div>
                  <div style={{ fontWeight: 700, fontSize: 18, color: "#D85A30", marginBottom: 4 }}>
                    Campaign Did Not Reach Goal
                  </div>
                  <div style={{ fontSize: 14, color: "#666" }}>
                    Go to the Refunds section to claim your contribution back
                  </div>
                </div>
              </div>
            )}
          </div>
 
          {/* Status Messages */}
          {status && (
            <div style={styles.messageBox("success")}>
              <span style={{ marginRight: 8 }}>✨</span>
              {status}
            </div>
          )}
          {error && (
            <div style={styles.messageBox("error")}>
              <span style={{ marginRight: 8 }}>⚠️</span>
              {error}
            </div>
          )}
        </div>
      </div>
 
      <style>{`
        @keyframes slideUp {
          from { opacity: 0; transform: translateY(20px); }
          to { opacity: 1; transform: translateY(0); }
        }
        @keyframes spin {
          from { transform: rotate(0deg); }
          to { transform: rotate(360deg); }
        }
      `}</style>
    </div>
  );
}
 
const styles = {
  mainCard: {
    background: "#fff",
    borderRadius: 24,
    padding: 48,
    boxShadow: "0 20px 60px rgba(127, 119, 221, 0.15), 0 0 1px rgba(0, 0, 0, 0.1)",
    border: "1px solid rgba(127, 119, 221, 0.15)"
  },
 
  title: {
    margin: "0 0 16px 0",
    fontSize: 42,
    fontWeight: 800,
    color: "#0f172a",
    letterSpacing: "-1px",
    lineHeight: 1.2
  },
 
  description: {
    margin: 0,
    fontSize: 18,
    color: "#64748b",
    lineHeight: 1.8,
    fontWeight: 400
  },
 
  statCard: {
    background: "linear-gradient(135deg, #f8f7ff 0%, #f3f0ff 100%)",
    borderRadius: 16,
    padding: 28,
    border: "1.5px solid rgba(127, 119, 221, 0.25)",
    position: "relative",
    overflow: "hidden",
    transition: "all 0.3s ease"
  },
 
  statBadge: {
    fontSize: 32,
    marginBottom: 12,
    display: "inline-block"
  },
 
  statLabel: {
    fontSize: 13,
    fontWeight: 700,
    color: "#7F77DD",
    letterSpacing: 1.2,
    marginBottom: 12,
    textTransform: "uppercase"
  },
 
  statValueLarge: {
    fontSize: 48,
    fontWeight: 800,
    color: "#0f172a",
    margin: 0,
    lineHeight: 1
  },
 
  statCurrency: {
    fontSize: 20,
    color: "#7F77DD",
    fontWeight: 700,
    marginTop: 4,
    marginBottom: 12
  },
 
  statSubtext: {
    fontSize: 14,
    color: "#94a3b8",
    fontWeight: 500
  },
 
  progressLabel: {
    fontSize: 13,
    fontWeight: 700,
    color: "#7F77DD",
    letterSpacing: 1,
    textTransform: "uppercase"
  },
 
  progressPercent: {
    fontSize: 28,
    fontWeight: 800,
    color: "#0f172a"
  },
 
  progressContainer: {
    width: "100%",
    height: 20,
    background: "#f1f5f9",
    borderRadius: 99,
    overflow: "hidden",
    marginBottom: 16,
    border: "1px solid rgba(127, 119, 221, 0.1)"
  },
 
  progressBar: {
    height: "100%",
    borderRadius: 99,
    transition: "width 0.6s cubic-bezier(0.4, 0, 0.2, 1)"
  },
 
  progressDescription: {
    fontSize: 14,
    color: "#64748b",
    margin: 0,
    fontWeight: 500
  },
 
  infoBox: {
    borderLeft: "5px solid #10B981",
    background: "linear-gradient(90deg, rgba(16, 185, 129, 0.08) 0%, rgba(16, 185, 129, 0.02) 100%)",
    padding: 24,
    borderRadius: 12,
    marginBottom: 0,
    border: "1px solid rgba(16, 185, 129, 0.2)"
  },
 
  infoLabel: {
    fontSize: 16,
    fontWeight: 700,
    color: "#0f172a"
  },
 
  infoSubtext: {
    fontSize: 14,
    color: "#64748b",
    marginTop: 6,
    fontWeight: 500
  },
 
  input: {
    display: "block",
    width: "100%",
    padding: "16px 20px",
    borderRadius: 12,
    border: "2px solid #e2e8f0",
    fontSize: 16,
    marginBottom: 16,
    boxSizing: "border-box",
    fontFamily: "inherit",
    transition: "all 0.3s ease",
    outline: "none",
    backgroundColor: "#f8fafc"
  },
 
  btn: {
    width: "100%",
    padding: "18px 24px",
    border: "none",
    borderRadius: 12,
    fontSize: 17,
    fontWeight: 700,
    cursor: "pointer",
    transition: "all 0.3s cubic-bezier(0.4, 0, 0.2, 1)",
    marginTop: 0,
    letterSpacing: "0.5px"
  },
 
  btnPrimary: {
    background: "linear-gradient(135deg, #7F77DD 0%, #6366F1 100%)",
    color: "#fff",
    boxShadow: "0 4px 12px rgba(127, 119, 221, 0.3)"
  },
 
  btnSuccess: {
    background: "linear-gradient(135deg, #10B981 0%, #059669 100%)",
    color: "#fff",
    boxShadow: "0 4px 12px rgba(16, 185, 129, 0.3)"
  },
 
  successBox: {
    background: "linear-gradient(90deg, rgba(16, 185, 129, 0.1) 0%, rgba(16, 185, 129, 0.05) 100%)",
    border: "1.5px solid rgba(16, 185, 129, 0.3)",
    borderRadius: 12,
    padding: 24,
    display: "flex",
    alignItems: "center",
    marginTop: 24
  },
 
  warningBox: {
    background: "linear-gradient(90deg, rgba(216, 90, 48, 0.1) 0%, rgba(216, 90, 48, 0.05) 100%)",
    border: "1.5px solid rgba(216, 90, 48, 0.3)",
    borderRadius: 12,
    padding: 24,
    display: "flex",
    alignItems: "center",
    marginTop: 24
  },
 
  messageBox: (type) => ({
    marginTop: 20,
    padding: 16,
    borderRadius: 10,
    fontSize: 15,
    fontWeight: 600,
    background: type === "success"
      ? "linear-gradient(90deg, rgba(16, 185, 129, 0.1) 0%, rgba(16, 185, 129, 0.05) 100%)"
      : "linear-gradient(90deg, rgba(216, 90, 48, 0.1) 0%, rgba(216, 90, 48, 0.05) 100%)",
    color: type === "success" ? "#059669" : "#D85A30",
    border: `1.5px solid ${type === "success" ? "rgba(16, 185, 129, 0.3)" : "rgba(216, 90, 48, 0.3)"}`,
    display: "flex",
    alignItems: "center"
  })

}

const cardStyle = { background: "#fff", border: "1px solid #eee", borderRadius: 12, padding: 24 };
const inputStyle = { display: "block", width: "100%", padding: "9px 12px", borderRadius: 8, border: "1px solid #ddd", fontSize: 14, marginBottom: 10, boxSizing: "border-box" };
const btnStyle = (bg) => ({ padding: "10px 20px", background: bg, color: "#fff", border: "none", borderRadius: 8, fontSize: 14, cursor: "pointer", marginRight: 8 });
